  "inlineSchema": "// Prisma schema for the X Clone project.\n// Uses SQLite as the database provider.\n//\n// Models:\n//   User            - Core user accounts with credentials (name, email, username, password, bio)\n//   Post            - User posts with content (max 280 chars), optional image\n//   Like            - Many-to-many likes between users and posts (unique per user+post)\n//   Bookmark        - Many-to-many bookmarks between users and posts (unique per user+post)\n//   Repost          - Many-to-many reposts between users and posts (unique per user+post)\n//   Comment         - Replies to posts (many-to-one with both User and Post)\n//   Follow          - Self-referential follow relationships between users\n//   Account/Session - NextAuth required models for session persistence\n//   VerificationToken - NextAuth model for email verification\n//   Conversation    - Direct messaging between two users\n//   ConversationParticipant - Links users to conversations\n//   Message         - Individual messages within a conversation\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id            String    @id @default(cuid())\n  name          String\n  email         String    @unique\n  emailVerified DateTime?\n  image         String?\n  bannerUrl     String?\n  username      String    @unique\n  bio           String?\n  password      String?\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n\n  posts              Post[]\n  likes              Like[]\n  bookmarks          Bookmark[]\n  reposts            Repost[]\n  comments           Comment[]\n  following          Follow[]                  @relation(\"following\")\n  followers          Follow[]                  @relation(\"followers\")\n  accounts           Account[] // ✅ opposite for Account.user\n  sessions           Session[] // ✅ opposite for Session.user\n  conversations      ConversationParticipant[]\n  sentMessages       Message[]\n  notifications      Notification[]            @relation(\"NotificationRecipient\")\n  actedNotifications Notification[]            @relation(\"NotificationActor\")\n}\n\nmodel Post {\n  id        String   @id @default(cuid())\n  content   String\n  imageUrl  String?\n  authorId  String\n  author    User     @relation(fields: [authorId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  likes         Like[]\n  bookmarks     Bookmark[]\n  reposts       Repost[]\n  comments      Comment[]\n  notifications Notification[]\n}\n\nmodel Like {\n  id        String   @id @default(cuid())\n  userId    String\n  postId    String\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, postId])\n}\n\nmodel Bookmark {\n  id        String   @id @default(cuid())\n  userId    String\n  postId    String\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, postId])\n}\n\nmodel Repost {\n  id        String   @id @default(cuid())\n  userId    String\n  postId    String\n  createdAt DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, postId])\n}\n\nmodel Comment {\n  id        String   @id @default(cuid())\n  content   String\n  userId    String\n  postId    String\n  createdAt DateTime @default(now())\n\n  user          User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  post          Post           @relation(fields: [postId], references: [id], onDelete: Cascade)\n  notifications Notification[]\n}\n\nmodel Follow {\n  id          String   @id @default(cuid())\n  followerId  String\n  followingId String\n  createdAt   DateTime @default(now())\n\n  follower  User @relation(\"following\", fields: [followerId], references: [id], onDelete: Cascade)\n  following User @relation(\"followers\", fields: [followingId], references: [id], onDelete: Cascade)\n\n  @@unique([followerId, followingId])\n}\n\n// Required for NextAuth PrismaAdapter\nmodel Account {\n  id                String  @id @default(cuid())\n  userId            String\n  type              String\n  provider          String\n  providerAccountId String\n  refresh_token     String?\n  access_token      String?\n  expires_at        Int?\n  token_type        String?\n  scope             String?\n  id_token          String?\n  session_state     String?\n  user              User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([provider, providerAccountId])\n}\n\nmodel Session {\n  id           String   @id @default(cuid())\n  sessionToken String   @unique\n  userId       String\n  expires      DateTime\n  user         User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel VerificationToken {\n  identifier String\n  token      String   @unique\n  expires    DateTime\n\n  @@unique([identifier, token])\n}\n\nmodel Conversation {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  participants ConversationParticipant[]\n  messages     Message[]\n}\n\nmodel ConversationParticipant {\n  id             String       @id @default(cuid())\n  userId         String\n  conversationId String\n  lastReadAt     DateTime?\n  user           User         @relation(fields: [userId], references: [id], onDelete: Cascade)\n  conversation   Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, conversationId])\n}\n\nmodel Message {\n  id             String   @id @default(cuid())\n  content        String\n  senderId       String\n  conversationId String\n  createdAt      DateTime @default(now())\n\n  sender       User         @relation(fields: [senderId], references: [id], onDelete: Cascade)\n  conversation Conversation @relation(fields: [conversationId], references: [id], onDelete: Cascade)\n}\n\nmodel Notification {\n  id        String   @id @default(cuid())\n  type      String // LIKE | REPOST | COMMENT | FOLLOW\n  read      Boolean  @default(false)\n  createdAt DateTime @default(now())\n\n  recipientId String\n  actorId     String\n  postId      String?\n  commentId   String?\n\n  recipient User     @relation(\"NotificationRecipient\", fields: [recipientId], references: [id], onDelete: Cascade)\n  actor     User     @relation(\"NotificationActor\", fields: [actorId], references: [id], onDelete: Cascade)\n  post      Post?    @relation(fields: [postId], references: [id], onDelete: SetNull)\n  comment   Comment? @relation(fields: [commentId], references: [id], onDelete: SetNull)\n\n  @@index([recipientId, read])\n  @@index([recipientId, createdAt])\n}\n",
